  ('elementary-7fec267e-moex-00334', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '下列關於加重結果犯之敘述，何者錯誤？', '["刑法第17條之加重結果犯，以能預見加重結果之發生為要件", "刑法第17條之加重結果犯係故意的基本犯罪與過失加重結果之結合犯罪", "不論法有無明文規定，客觀上可能預見加重結果，即足以構成加重結果犯", "就加重結果之發生，具有主觀過失，方能構成"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:59+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00335', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '公務員甲因需錢孔急，乃與非公務員之友人乙商量，由乙侵占其所任職公司業務上所管領之現金新臺幣 5百萬元得逞，供2人平分花用，依實務見解下列敘述何者正確？', '["甲成立普通侵占罪", "甲成立公務侵占罪", "甲與乙成立業務侵占罪之共同正犯", "甲成立業務侵占罪之事後幫助犯"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:59+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00336', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '關於故意與過失，下列敘述何者正確？', '["行為人對於構成犯罪之事實，雖預見其能發生而確信其不發生者，以故意論", "行為人對於構成犯罪之事實，預見其發生而其發生並不違背其本意者，以過失論", "故意可分為有認識之故意與無認識之故意", "故意可分為直接故意與間接故意"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:59+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
